            if (verification.isBlank()) verification = "Contrôler les produits sensibles, les quantités et l’ordonnance.";
            if (resume.isBlank()) resume = content;
            if (risques.isBlank()) risques = "Aucun risque évident détecté, mais une vérification pharmacien reste nécessaire.";
            if (action.isBlank()) action = "Valider seulement après vérification pharmacien.";
            if (confiance.isBlank()) confiance = "Moyenne";

            return AnalyseResult.ok(
                    decision,
                    score,
                    priorite,
                    ordonnance,
                    doublon,
                    interaction,
                    verification,
                    resume,
                    risques,
                    action,
                    confiance
            );

        } catch (Exception e) {
            System.err.println("[Groq Commande] Erreur : " + e.getMessage());
            return AnalyseResult.fail(e.getMessage());
        }
    }

    private String construirePromptCommande(Commande commande) {
        StringBuilder sb = new StringBuilder();

        sb.append("Analyse cette commande de pharmacie pour aider le pharmacien.\n\n");

        sb.append("=== COMMANDE ===\n");
        sb.append("ID : ").append(commande.getId_commande()).append("\n");
        sb.append("Statut : ").append(safe(commande.getStatut_commande())).append("\n");
        sb.append("Date : ").append(commande.getDate_creation_commande()).append("\n");
        sb.append("Montant total : ")
                .append(String.format("%.2f Dt", commande.getMontant_total_cents() / 100.0))
                .append("\n\n");

        User user = commande.getUser();

        sb.append("=== CLIENT ===\n");

        if (user != null) {
            String nom = safe(user.getPrenom()) + " " + safe(user.getNom());
            sb.append("Nom : ").append(nom.trim().isBlank() ? "Client inconnu" : nom.trim()).append("\n");
            sb.append("Email : ").append(safe(user.getEmailUser())).append("\n");
            sb.append("Adresse : ").append(safe(user.getAdresseUser())).append("\n");
        } else {
            sb.append("Client : introuvable\n");
        }

        sb.append("\n=== PRODUITS COMMANDÉS ===\n");

        List<CommandeProduit> produits = commande.getCommande_produits();

        if (produits == null || produits.isEmpty()) {
            sb.append("Aucun produit trouvé.\n");
        } else {
            for (CommandeProduit cp : produits) {
                Produit p = cp.getProduit();

                if (p == null) {
                    sb.append("- Produit introuvable\n");
                    continue;
                }

                sb.append("- Nom : ").append(safe(p.getNom_produit())).append("\n");
                sb.append("  Catégorie : ").append(safe(p.getCategorie_produit())).append("\n");
                sb.append("  Quantité : ").append(cp.getQuantite_commandee()).append("\n");
                sb.append("  Prix unitaire : ").append(String.format("%.2f Dt", p.getPrix_produit())).append("\n");
                sb.append("  Sous-total : ")
                        .append(String.format("%.2f Dt", p.getPrix_produit() * cp.getQuantite_commandee()))
                        .append("\n\n");
            }
        }

        sb.append("""

                Fais une analyse utile pour le pharmacien.
                Cherche surtout :
                1. Médicaments sensibles ou à ordonnance.
                2. Doublons de produits.
                3. Quantités suspectes.
                4. Interactions possibles.
                5. Décision claire : valider, vérifier, bloquer temporairement.
                6. Score sécurité sur 10.
                """);

        return sb.toString();
    }

    private String getGroqApiKey() {
        String key = firstNonBlank(
                EnvLoader.get("GROQ_API_KEY_produit"),
                EnvLoader.get("GROQ_API_KEY")
        );

        if (key == null) return null;

        key = key.trim();

        if ((key.startsWith("\"") && key.endsWith("\"")) ||
                (key.startsWith("'") && key.endsWith("'"))) {
            key = key.substring(1, key.length() - 1).trim();
        }

        return key;
    }

    private String firstNonBlank(String... values) {
        if (values == null) {
            return null;
        }

        for (String value : values) {
            if (value != null && !value.isBlank()) {
                return value;
            }
        }

        return null;
    }

    private String extractContentFromGroqResponse(String json) {
        Pattern pattern = Pattern.compile(
                "\"content\"\\s*:\\s*\"((?:\\\\.|[^\"\\\\])*)\"",
                Pattern.DOTALL
        );

        Matcher matcher = pattern.matcher(json);

        if (matcher.find()) {
            return jsonUnescape(matcher.group(1));
        }

        return null;
    }

    private String extractSection(String text, String start, String end) {
        if (text == null) return "";

        String regex;

        if (end == null) {
            regex = "(?is)" + Pattern.quote(start) + "\\s*:\\s*(.*)$";
        } else {
            regex = "(?is)" + Pattern.quote(start) + "\\s*:\\s*(.*?)\\s*" + Pattern.quote(end) + "\\s*:";
        }

        Matcher matcher = Pattern.compile(regex).matcher(text);

        if (matcher.find()) {
            return matcher.group(1).trim();
        }

        return "";
    }

    private String readAll(InputStream inputStream) throws Exception {
        if (inputStream == null) return "";

        StringBuilder sb = new StringBuilder();

        try (BufferedReader br = new BufferedReader(
                new InputStreamReader(inputStream, StandardCharsets.UTF_8)
        )) {
            String line;

            while ((line = br.readLine()) != null) {
                sb.append(line);
            }
        }

        return sb.toString();
    }

    private String jsonEscape(String s) {
        if (s == null) return "";

        return s
                .replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\r", "\\r")
                .replace("\n", "\\n")
                .replace("\t", "\\t");
    }

    private String jsonUnescape(String s) {
        if (s == null) return "";

        return s
                .replace("\\n", "\n")
                .replace("\\r", "\r")
                .replace("\\t", "\t")
                .replace("\\\"", "\"")
                .replace("\\\\", "\\");
    }

    private String safe(String value) {
        return value == null ? "" : value;
    }
}

package tn.esprit.services;

import com.stripe.Stripe;
import com.stripe.exception.StripeException;
import com.stripe.model.checkout.Session;
import com.stripe.param.checkout.SessionCreateParams;
import com.stripe.param.checkout.SessionRetrieveParams;
import tn.esprit.config.StripeConfig;
import tn.esprit.entities.CommandeProduit;
import tn.esprit.entities.Produit;
import tn.esprit.entities.User;

import java.util.ArrayList;
import java.util.List;

public class StripeCheckoutService {

    public StripeCheckoutService() {
        Stripe.apiKey = StripeConfig.SECRET_KEY;
    }

    public Session creerSessionCheckout(
            User user,
            List<CommandeProduit> lignes,
            int localCommandeId
    ) throws StripeException {

        List<SessionCreateParams.LineItem> stripeItems = new ArrayList<>();

        for (CommandeProduit cp : lignes) {
            Produit p = cp.getProduit();

            SessionCreateParams.LineItem item =
                    SessionCreateParams.LineItem.builder()
                            .setQuantity((long) cp.getQuantite_commandee())
                            .setPriceData(
                                    SessionCreateParams.LineItem.PriceData.builder()
                                            .setCurrency("usd") // USD (Stripe supporte l'USD, TND nécessite une configuration compte)
                                            .setUnitAmount((long) Math.round(p.getPrix_produit() * 100))
                                            .setProductData(
                                                    SessionCreateParams.LineItem.PriceData.ProductData.builder()
                                                            .setName(p.getNom_produit())
                                                            .build()
                                            )
                                            .build()
                            )
                            .build();

            stripeItems.add(item);
        }

        String successUrl = StripeConfig.BASE_URL
                + "/stripe/success?session_id={CHECKOUT_SESSION_ID}&commande_id=" + localCommandeId;

        String cancelUrl = StripeConfig.BASE_URL
                + "/stripe/cancel?commande_id=" + localCommandeId;

        SessionCreateParams params = SessionCreateParams.builder()
                .setMode(SessionCreateParams.Mode.PAYMENT)
                .setSuccessUrl(successUrl)
                .setCancelUrl(cancelUrl)
                .setCustomerEmail(user.getEmailUser())
                .setClientReferenceId(String.valueOf(localCommandeId))
                .putMetadata("commande_id", String.valueOf(localCommandeId))
                .addAllLineItem(stripeItems)
                .build();

        return Session.create(params);
    }

    public Session recupererSession(String sessionId) throws StripeException {
        return Session.retrieve(sessionId, SessionRetrieveParams.builder().build(), null);
    }

    public boolean paiementConfirme(String sessionId) throws StripeException {
        Session session = recupererSession(sessionId);
        return "paid".equalsIgnoreCase(session.getPaymentStatus());
    }
}

package tn.esprit.services;

import com.stripe.Stripe;
import com.stripe.exception.StripeException;
import com.stripe.model.checkout.Session;
import com.stripe.param.checkout.SessionCreateParams;
import com.stripe.param.checkout.SessionRetrieveParams;
import tn.esprit.config.StripeConfig;
import tn.esprit.entities.CommandeProduit;
import tn.esprit.entities.Produit;
import tn.esprit.entities.User;

import java.util.ArrayList;
import java.util.List;

public class StripeCheckoutService {

    public StripeCheckoutService() {
        configureStripeApiKey();
    }

    public Session creerSessionCheckout(
            User user,
            List<CommandeProduit> lignes,
            int localCommandeId
    ) throws StripeException {

        configureStripeApiKey();

        if (Stripe.apiKey == null || Stripe.apiKey.isBlank()) {
            throw new IllegalStateException("Clé Stripe manquante. Configurez STRIPE_SECRET_KEY dans .env.local ou IntelliJ.");
        }

        List<SessionCreateParams.LineItem> stripeItems = new ArrayList<>();

        for (CommandeProduit cp : lignes) {
            Produit p = cp.getProduit();

            SessionCreateParams.LineItem item =
                    SessionCreateParams.LineItem.builder()
                            .setQuantity((long) cp.getQuantite_commandee())
                            .setPriceData(
                                    SessionCreateParams.LineItem.PriceData.builder()
                                            .setCurrency("usd") // USD (Stripe supporte l'USD, TND nécessite une configuration compte)
                                            .setUnitAmount(Math.round(p.getPrix_produit() * 100))
                                            .setProductData(
                                                    SessionCreateParams.LineItem.PriceData.ProductData.builder()
                                                            .setName(p.getNom_produit())
                                                            .build()
                                            )
                                            .build()
                            )
                            .build();

            stripeItems.add(item);
        }

        String successUrl = StripeConfig.getBaseUrl()
                + "/stripe/success?session_id={CHECKOUT_SESSION_ID}&commande_id=" + localCommandeId;

        String cancelUrl = StripeConfig.getBaseUrl()
                + "/stripe/cancel?commande_id=" + localCommandeId;

        SessionCreateParams params = SessionCreateParams.builder()
                .setMode(SessionCreateParams.Mode.PAYMENT)
                .setSuccessUrl(successUrl)
                .setCancelUrl(cancelUrl)
                .setCustomerEmail(user.getEmailUser())
                .setClientReferenceId(String.valueOf(localCommandeId))
                .putMetadata("commande_id", String.valueOf(localCommandeId))
                .addAllLineItem(stripeItems)
                .build();

        return Session.create(params);
    }

    private void configureStripeApiKey() {
        String secretKey = StripeConfig.getSecretKey();
        Stripe.apiKey = secretKey;
        System.out.println("[Stripe] STRIPE_SECRET_KEY = " + (hasText(secretKey) ? mask(secretKey) : "MANQUANTE"));
    }

    private boolean hasText(String value) {
        return value != null && !value.isBlank();
    }

    private String mask(String value) {
        String trimmed = value.trim();
        if (trimmed.length() <= 8) {
            return "********";
        }
        return trimmed.substring(0, 4) + "..." + trimmed.substring(trimmed.length() - 4);
    }

    public Session recupererSession(String sessionId) throws StripeException {
        return Session.retrieve(sessionId, SessionRetrieveParams.builder().build(), null);
    }

    public boolean paiementConfirme(String sessionId) throws StripeException {
        Session session = recupererSession(sessionId);
        return "paid".equalsIgnoreCase(session.getPaymentStatus());
    }
}

package tn.esprit.tools;

import java.io.BufferedReader;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.Locale;

/**
 * Utilitaire pour charger les variables d'environnement depuis le fichier .env.local
 * Appeler EnvLoader.load() au démarrage de l'application
 */
public class EnvLoader {

    /**
     * Charge les variables d'environnement depuis .env.local ou .env
     * Remplace les variable d'environnement système si elles existent dans le fichier
     */
    public static void load() {
        String[] possiblePaths = {
                ".env.local",
                ".env"
        };

        for (String path : possiblePaths) {
            try (BufferedReader br = Files.newBufferedReader(Paths.get(path))) {
                String line;
                while ((line = br.readLine()) != null) {
                    line = line.trim();

                    // Ignorer les commentaires et lignes vides
                    if (line.isEmpty() || line.startsWith("#")) {
                        continue;
                    }

                    // Parser les variables KEY=VALUE
                    int eqIndex = line.indexOf('=');
                    if (eqIndex > 0) {
                        String key = line.substring(0, eqIndex).trim();
                        String value = line.substring(eqIndex + 1).trim();

                        // Retirer les guillemets si présents
                        if (value.startsWith("\"") && value.endsWith("\"")) {
                            value = value.substring(1, value.length() - 1);
                        }

                        publishPropertyAliases(key, value);

                        System.out.println("[EnvLoader] Charged: " + key);
                    }
                }
                System.out.println("[EnvLoader] Loaded environment from: " + path);
                return;
            } catch (IOException ignored) {
                // Fichier non trouvé, continuation
            }
        }
    }

    private static void publishPropertyAliases(String key, String value) {
        if (key == null || key.isBlank()) {
            return;
        }

        String trimmedKey = key.trim();
        String normalized = trimmedKey.toLowerCase(Locale.ROOT);

        System.setProperty(trimmedKey, value);
        System.setProperty(normalized, value);
        System.setProperty(normalized.replace('_', '.'), value);

        switch (trimmedKey) {
            case "BREVO_API_KEY" -> System.setProperty("brevo.api.key", value);
            case "BREVO_SENDER_EMAIL" -> System.setProperty("brevo.sender.email", value);
            case "BREVO_SENDER_NAME" -> System.setProperty("brevo.sender.name", value);
            case "BREVO_API_URL" -> System.setProperty("brevo.api.url", value);
            case "MEDFLOW_MAIL_USER" -> System.setProperty("mail.user", value);
            case "RECAPTCHA_SITE_KEY" -> System.setProperty("recaptcha.siteKey", value);
            case "RECAPTCHA_SECRET_KEY" -> System.setProperty("recaptcha.secretKey", value);
            default -> {
            }
        }
    }
}

package tn.esprit.tools;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Locale;

import javax.xml.parsers.DocumentBuilderFactory;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

/**
 * Utilitaire pour charger les variables d'environnement depuis le fichier .env.local
 * Appeler EnvLoader.load() au démarrage de l'application
 */
public class EnvLoader {

    private static final String[] POSSIBLE_ENV_FILES = {
            ".env.local",
            ".env"
    };

    private static final String[] POSSIBLE_INTELLIJ_FILES = {
            ".idea/runConfigurations/MainFx.xml",
            ".idea/workspace.xml"
    };

    /**
     * Charge les variables d'environnement depuis .env.local ou .env
     * Remplace les variable d'environnement système si elles existent dans le fichier
     */
    public static void load() {
        publishCurrentEnvironment();

        for (String path : POSSIBLE_ENV_FILES) {
            try (BufferedReader br = Files.newBufferedReader(Paths.get(path))) {
                String line;
                while ((line = br.readLine()) != null) {
                    line = line.trim();

                    // Ignorer les commentaires et lignes vides
                    if (line.isEmpty() || line.startsWith("#")) {
                        continue;
                    }

                    // Parser les variables KEY=VALUE
                    int eqIndex = line.indexOf('=');
                    if (eqIndex > 0) {
                        String key = line.substring(0, eqIndex).trim();
                        String value = line.substring(eqIndex + 1).trim();

                        // Retirer les guillemets si présents
                        if (value.startsWith("\"") && value.endsWith("\"")) {
                            value = value.substring(1, value.length() - 1);
                        }

                        publishPropertyAliases(key, value);

                        System.out.println("[EnvLoader] Charged: " + key);
                    }
                }
                System.out.println("[EnvLoader] Loaded environment from: " + path);
            } catch (IOException ignored) {
                // Fichier non trouvé, continuation
            }
        }

        for (String path : POSSIBLE_INTELLIJ_FILES) {
            loadIntelliJEnvFile(Paths.get(path));
        }
    }

    public static String get(String key) {
        return get(key, null);
    }

    public static String get(String key, String defaultValue) {
        String value = firstNonBlank(
                System.getenv(key),
                System.getProperty(key),
                System.getProperty(key.toLowerCase(Locale.ROOT)),
                System.getProperty(key.toLowerCase(Locale.ROOT).replace('_', '.'))
        );
        return value != null ? value : defaultValue;
    }

    private static void publishCurrentEnvironment() {
        for (var entry : System.getenv().entrySet()) {
            publishPropertyAliases(entry.getKey(), entry.getValue());
        }
    }

    private static void loadIntelliJEnvFile(Path path) {
        if (path == null || !Files.exists(path)) {
            return;
        }

        try (InputStream input = Files.newInputStream(path)) {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setExpandEntityReferences(false);

            Document document = factory.newDocumentBuilder().parse(input);
            NodeList envNodes = document.getElementsByTagName("env");

            for (int i = 0; i < envNodes.getLength(); i++) {
                Element env = (Element) envNodes.item(i);
                publishPropertyAliases(env.getAttribute("name"), env.getAttribute("value"));
            }

            if (envNodes.getLength() > 0) {
                System.out.println("[EnvLoader] Loaded IntelliJ envs from: " + path);
            }
        } catch (Exception e) {
            System.err.println("[EnvLoader] Impossible de lire " + path + " : " + e.getMessage());
        }
    }

    private static void publishPropertyAliases(String key, String value) {
        if (key == null || key.isBlank()) {
            return;
        }

        String trimmedKey = key.trim();
        String trimmedValue = value == null ? "" : value.trim();
        String normalized = trimmedKey.toLowerCase(Locale.ROOT);

        publishIfMissing(trimmedKey, trimmedValue);
        publishIfMissing(normalized, trimmedValue);
        publishIfMissing(normalized.replace('_', '.'), trimmedValue);

        switch (trimmedKey) {
            case "BREVO_API_KEY" -> publishIfMissing("brevo.api.key", trimmedValue);
            case "BREVO_SENDER_EMAIL" -> publishIfMissing("brevo.sender.email", trimmedValue);
            case "BREVO_SENDER_NAME" -> publishIfMissing("brevo.sender.name", trimmedValue);
            case "BREVO_API_URL" -> publishIfMissing("brevo.api.url", trimmedValue);
            case "MEDFLOW_MAIL_USER" -> publishIfMissing("mail.user", trimmedValue);
            case "RECAPTCHA_SITE_KEY" -> publishIfMissing("recaptcha.siteKey", trimmedValue);
            case "RECAPTCHA_SECRET_KEY" -> publishIfMissing("recaptcha.secretKey", trimmedValue);
            default -> {
            }
        }
    }

    private static void publishIfMissing(String key, String value) {
        if (key == null || key.isBlank() || value == null || value.isBlank()) {
            return;
        }

        String existing = System.getProperty(key);
        if (existing == null || existing.isBlank()) {
            System.setProperty(key, value);
        }
    }

    private static String firstNonBlank(String... values) {
        if (values == null) {
            return null;
        }

        for (String value : values) {
            if (value != null && !value.isBlank()) {
                return value;
            }
        }

        return null;
    }
}
